{"code": "# Read Europe metadata
import json, re

europe_metadata = locals()['var_functions.query_db:16']
if isinstance(europe_metadata, str):
    with open(europe_metadata, 'r') as f:
        europe_metadata = json.load(f)

# Group by year and collect article IDs
europe_by_year = {}
all_europe_ids = set()
years = range(2010, 2021)

for y in years:
    europe_by_year[y] = set()

for item in europe_metadata:
    year = int(item['publication_date'][:4])
    article_id = str(item['article_id'])
    if 2010 <= year <= 2020:
        europe_by_year[year].add(article_id)
        all_europe_ids.add(article_id)

print('__RESULT__:')
print(json.dumps({
    'unique_ids': len(all_europe_ids),
    'year_counts': {y: len(europe_by_year[y]) for y in years}
}))"}

