    all_europe_ids.extend(europe_articles_by_year[y])

print('__RESULT__:')
print(json.dumps({
    'total_articles': len(all_europe_ids),
    'by_year': {y: len(europe_articles_by_year[y]) for y in years},
    'sample_ids': all_europe_ids[:5]
}))"}

