{"code": "import json
import re
from collections import defaultdict

# Load Europe metadata
europe_metadata = locals()['var_functions.query_db:16']
if isinstance(europe_metadata, str):
    with open(europe_metadata, 'r') as f:
        europe_metadata = json.load(f)

# Group European articles by year
year_to_article_ids = defaultdict(list)
target_years = range(2010, 2021)

for y in target_years:
    year_to_article_ids[y] = []

for item in europe_metadata:
    year = int(item['publication_date'][:4])
    article_id = item['article_id']
    if 2010 <= year <= 2020:
        year_to_article_ids[year].append(article_id)

# Total European articles for 2010-2020
total_europe_articles = sum(len(ids) for ids in year_to_article_ids.values())

print('__RESULT__:')
print(json.dumps({
    'timeframe': '2010-2020',
    'total_europe_articles': total_europe_articles,
    'by_year_initial': {y: len(ids) for y, ids in year_to_article_ids.items()}
}))"}

{"code": "# Check if MongoDB articles result is stored in a file
import json, os, pathlib

def load_full_result(storage_var):
    if isinstance(storage_var, str) and pathlib.Path(storage_var).exists():
        with open(storage_var, 'r') as f:
            return json.load(f)
    elif isinstance(storage_var, list):
        return storage_var
    else:
        return storage_var

# Try to find if there's a file path for articles
articles_result = locals()['var_functions.query_db:70']
articles_data = load_full_result(articles_result)

print('__RESULT__:')
print(json.dumps({
    'articles_type': type(articles_result).__name__,
    'is_file_path': isinstance(articles_result, str) and pathlib.Path(articles_result).exists(),
    'article_count': len(articles_data) if isinstance(articles_data, list) else 'N/A',
    'first_article': articles_data[0] if isinstance(articles_data, list) and len(articles_data) > 0 else None
}))"}

